package com.evolua.auth.infrastructure.persistence; import com.evolua.auth.domain.AuthUser; import com.evolua.auth.domain.AuthUserRepository; import com.evolua.auth.domain.RefreshSession; import com.evolua.auth.domain.RefreshSessionRepository; import java.util.List; import java.util.Optional; import org.springframework.stereotype.Repository; @Repository public class AuthPersistenceAdapter implements AuthUserRepository, RefreshSessionRepository { private final AuthUserJpaRepository authUserJpaRepository; private final RefreshSessionJpaRepository refreshSessionJpaRepository; public AuthPersistenceAdapter(AuthUserJpaRepository authUserJpaRepository, RefreshSessionJpaRepository refreshSessionJpaRepository) { this.authUserJpaRepository = authUserJpaRepository; this.refreshSessionJpaRepository = refreshSessionJpaRepository; } public AuthUser save(AuthUser user) { AuthUserEntity entity = new AuthUserEntity(); entity.setId(user.id()); entity.setUserId(user.userId()); entity.setEmail(user.email()); entity.setPasswordHash(user.passwordHash()); entity.setRoles(String.join(",", user.roles())); entity.setCreatedAt(user.createdAt()); AuthUserEntity saved = authUserJpaRepository.save(entity); return new AuthUser(saved.getId(), saved.getUserId(), saved.getEmail(), saved.getPasswordHash(), List.of(saved.getRoles().split(",")), saved.getCreatedAt()); } public Optional<AuthUser> findByEmail(String email) { return authUserJpaRepository.findByEmail(email).map(saved -> new AuthUser(saved.getId(), saved.getUserId(), saved.getEmail(), saved.getPasswordHash(), List.of(saved.getRoles().split(",")), saved.getCreatedAt())); } public Optional<AuthUser> findByUserId(String userId) { return authUserJpaRepository.findByUserId(userId).map(saved -> new AuthUser(saved.getId(), saved.getUserId(), saved.getEmail(), saved.getPasswordHash(), List.of(saved.getRoles().split(",")), saved.getCreatedAt())); } public RefreshSession save(RefreshSession session) { RefreshSessionEntity entity = new RefreshSessionEntity(); entity.setId(session.id()); entity.setUserId(session.userId()); entity.setRefreshToken(session.refreshToken()); entity.setCreatedAt(session.createdAt()); entity.setRevoked(session.revoked()); RefreshSessionEntity saved = refreshSessionJpaRepository.save(entity); return new RefreshSession(saved.getId(), saved.getUserId(), saved.getRefreshToken(), saved.getCreatedAt(), saved.isRevoked()); } public Optional<RefreshSession> findByRefreshToken(String refreshToken) { return refreshSessionJpaRepository.findByRefreshToken(refreshToken).map(saved -> new RefreshSession(saved.getId(), saved.getUserId(), saved.getRefreshToken(), saved.getCreatedAt(), saved.isRevoked())); } public void revokeAll(String userId) { for (RefreshSessionEntity session : refreshSessionJpaRepository.findAllByUserId(userId)) { session.setRevoked(true); refreshSessionJpaRepository.save(session); } } }
